UC_WEEKLY_VENDOR_THIRD_PARTY_OAUTH_APP_O.defender_kql:
let _Lookback = 14d;
let _Baseline = 30d;
let _CorrWindow = 30m;
let _MinObjects = 50;
let _MinDistinct = 25;
let _FirstPartyApps = dynamic(["Office 365","Microsoft Teams","Microsoft Outlook","SharePoint Online","OneDrive","Microsoft 365 Apps","Microsoft Graph PowerShell","Microsoft Authentication Broker","Microsoft Edge","Windows Sign In"]);
// Stage 1 — baseline of (AppId, IPAddress) pairs seen in the prior 30d window
let _Baseline_Pairs =
    AADSignInEventsBeta
    | where Timestamp between (ago(_Baseline) .. ago(_Lookback))
    | where ErrorCode == 0
    | summarize Seen = count() by ApplicationId, IPAddress
    | where Seen > 2;
// Stage 1 — recent successful auths from (AppId, IPAddress) pairs NOT in the baseline
let SuspectAuth =
    AADSignInEventsBeta
    | where Timestamp > ago(_Lookback)
    | where ErrorCode == 0
    | where Application !in~ (_FirstPartyApps)
    | where ClientAppUsed in ("Other clients","Browser","Mobile Apps and Desktop clients")
    | join kind=leftanti _Baseline_Pairs on ApplicationId, IPAddress
    | project SignInTime = Timestamp, AccountObjectId, AccountUpn,
              Application, ApplicationId, AuthIPAddress = IPAddress, Country;
// Stage 2 — bulk SaaS object reads by the same actor within 30 minutes of the suspicious sign-in
CloudAppEvents
| where Timestamp > ago(_Lookback)
| where ActionType in~ ("FileDownloaded","FileAccessed","FilePreviewed","FileSyncDownloadedFull","MailItemsAccessed","SearchQueryPerformed","MessageRead","Download","RepoCloned","RepoArchiveDownload","SecretRead","Export")
| join kind=inner SuspectAuth on $left.AccountObjectId == $right.AccountObjectId
| where Timestamp between (SignInTime .. SignInTime + _CorrWindow)
| summarize ObjectsRead = count(),
            DistinctObjects = dcount(ObjectName),
            Actions = make_set(ActionType, 12),
            SampleObjects = make_set(ObjectName, 10),
            SaaSApps = make_set(Application, 6),
            FirstAction = min(Timestamp),
            LastAction  = max(Timestamp)
            by AccountObjectId, AccountUpn, Application, ApplicationId, AuthIPAddress, Country, SignInTime
| where ObjectsRead >= _MinObjects or DistinctObjects >= _MinDistinct
| project SignInTime, FirstAction, LastAction, AccountUpn, Application,
          AuthIPAddress, Country, ObjectsRead, DistinctObjects,
          Actions, SaaSApps, SampleObjects
| order by FirstAction desc

